// ===== Core decrypt functions =====

async function expandSeed(seed: Uint8Array, key: number, bonusSeed?: Uint8Array): Promise<Uint8Array> {
  const expanded = new Uint8Array(0x90);
  for (let i = 0; i < 0x90; i += 0x10) {
    expanded.set(seed, i);
    expanded[i] = i / 0x10;
  }
  const decrypted = await kirk7(expanded, key);
  if (bonusSeed) {
    for (let i = 0; i < 0x90; i++) {
      decrypted[i]! ^= bonusSeed[i % 0x10]!;
    }
  }
  return decrypted;
}

async function decryptKirkHeader(inbuf: Uint8Array, xorbufStart: number, xorbuf: Uint8Array, key: number): Promise<Uint8Array> {
  const outbuf = new Uint8Array(0x40);
  for (let i = 0; i < 0x40; i++) {
    outbuf[i] = inbuf[i]! ^ xorbuf[xorbufStart + i]!;
  }
  const decrypted = await kirk7(outbuf, key);
  for (let i = 0; i < 0x40; i++) {
    decrypted[i]! ^= xorbuf[xorbufStart + 0x40 + i]!;
  }
  return decrypted;
}

async function decryptKirkHeaderType0(inbuf: Uint8Array, xorbuf: Uint8Array, key: number): Promise<Uint8Array> {
  const outbuf = new Uint8Array(0x70);
  for (let i = 0; i < 0x70; i++) {
    outbuf[i] = inbuf[i]! ^ xorbuf[i + 0x14]!;
  }
  const decrypted = await kirk7(outbuf, key);
  for (let i = 0; i < 0x70; i++) {
    decrypted[i]! ^= xorbuf[i + 0x20]!;
  }
  return decrypted;
}

// PSP_Header size = 0x150, KIRK_CMD1_HEADER size = 0x90
const PSP_HEADER_SIZE = 0x150;
const KIRK_CMD1_HEADER_SIZE = 0x90;
const KIRK_CMD1_ECDSA_HEADER_SIZE = 0x90;
const PRX_HEADER_SIZE = 0x80;

// ===== PRX Type builders =====

function buildPRXType0(prx: Uint8Array) {
  const tag = prx.slice(0xD0, 0xD4);
  const sha1Hash = prx.slice(0xD4, 0xE8);
  const unused = prx.slice(0xE8, 0x110);
  const kirkBlock = new Uint8Array(0x90);
  kirkBlock.set(prx.slice(0x110, 0x150), 0);       // key data at 0..0x40
  kirkBlock.set(prx.slice(0x80, 0x80 + 0x50), 0x40); // rest from 0x80
  const prxHeader = prx.slice(0, 0x80);
  return { tag, sha1Hash, unused, kirkBlock, prxHeader };
}

function buildPRXType2(prx: Uint8Array) {
  const tag = prx.slice(0xD0, 0xD4);
  const empty = new Uint8Array(0x58);
  const id = prx.slice(0x140, 0x150).slice();
  const sha1Hash = prx.slice(0x12C, 0x140).slice();
  const kirkHeader = new Uint8Array(0x40);
  kirkHeader.set(prx.slice(0x80, 0xB0), 0);        // 0x30 bytes
  kirkHeader.set(prx.slice(0xC0, 0xD0), 0x30);     // 0x10 bytes
  const kirkMetadata = prx.slice(0xB0, 0xC0).slice();
  const prxHeader = prx.slice(0, 0x80).slice();
  return { tag, empty, id, sha1Hash, kirkHeader, kirkMetadata, prxHeader };
}

function buildPRXType6(prx: Uint8Array) {
  const tag = prx.slice(0xD0, 0xD4);
  const empty = new Uint8Array(0x38);
  const ecdsaSignatureTail = prx.slice(0x10C, 0x12C).slice();
  const id = prx.slice(0x140, 0x150).slice();
  const sha1Hash = prx.slice(0x12C, 0x140).slice();
  const kirkHeader = new Uint8Array(0x40);
  kirkHeader.set(prx.slice(0x80, 0xB0), 0);
  kirkHeader.set(prx.slice(0xC0, 0xD0), 0x30);
  const kirkMetadata = prx.slice(0xB0, 0xC0).slice();
  const prxHeader = prx.slice(0, 0x80).slice();
  return { tag, empty, ecdsaSignatureTail, id, sha1Hash, kirkHeader, kirkMetadata, prxHeader };
}

// ===== Decrypt type functions =====

async function pspDecryptType0(inbuf: Uint8Array, size: number): Promise<number> {
  const decryptSize = readU32LE(inbuf, 0xB0) | 0; // signed
  const tag = readU32LE(inbuf, 0xD0);
  const pti = getTagInfo(tag);
  if (!pti) return -1;

  // xorbuf = pre-decrypted key (144 bytes)
  const xorbuf = pti.key;

  const type0 = buildPRXType0(inbuf);

  // SHA1 verification
  const shaData = concatBytes(xorbuf.slice(0, 0x14), type0.unused, type0.kirkBlock, type0.prxHeader);
  log.debug(`type0: shaData length=${shaData.length} (expect 0x14C=${0x14C})`);
  log.debug(`type0: xorbuf[0:20]=${Array.from(xorbuf.slice(0,20)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type0: unused[0:8]=${Array.from(type0.unused.slice(0,8)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type0: kirkBlock[0:16]=${Array.from(type0.kirkBlock.slice(0,16)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type0: prxHeader[0:16]=${Array.from(type0.prxHeader.slice(0,16)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  const computedSha1 = await sha1(shaData);
  log.debug(`type0: computed SHA1=${Array.from(computedSha1).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type0: expected SHA1=${Array.from(type0.sha1Hash).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  if (!arraysEqual(computedSha1, type0.sha1Hash)) return -3;

  // Build kirk CMD1 buffer
  const offset = PSP_HEADER_SIZE - KIRK_CMD1_HEADER_SIZE - PRX_HEADER_SIZE;
  const outbuf = new Uint8Array(size);
  outbuf.set(inbuf.subarray(0, size));

  // Place kirkBlock as header, then prxHeader after it
  const headerBuf = new Uint8Array(KIRK_CMD1_HEADER_SIZE + PRX_HEADER_SIZE);
  headerBuf.set(type0.kirkBlock, 0);
  headerBuf.set(type0.prxHeader, KIRK_CMD1_HEADER_SIZE);

  // Decrypt kirk header (type 0 style)
  const decryptedHeader = await decryptKirkHeaderType0(type0.kirkBlock, xorbuf, pti.code);
  headerBuf.set(decryptedHeader, 0);

  outbuf.set(headerBuf, offset);

  // kirkCMD1
  const kirkInput = outbuf.slice(offset, size);
  const decrypted = await kirkCMD1(kirkInput);
  if (!decrypted) return -4;

  inbuf.set(decrypted, 0);
  return decryptSize;
}

async function pspDecryptType1(inbuf: Uint8Array, size: number): Promise<number> {
  const decryptSize = readU32LE(inbuf, 0xB0) | 0;
  const tag = readU32LE(inbuf, 0xD0);
  const pti = getTagInfo(tag);
  if (!pti) return -1;

  const xorbuf = pti.key;
  const type1 = buildPRXType0(inbuf); // same layout as type0

  // Type1 extra decrypt: kirk7 on sha1+0xC for 0xA0 bytes
  const sha1PlusBlock = new Uint8Array(0xA0);
  // sha1Hash starts at offset 0 in type1 data, +0xC offset
  const srcOffset = 0xC;
  sha1PlusBlock.set(type1.sha1Hash.subarray(srcOffset), 0);
  sha1PlusBlock.set(type1.unused, type1.sha1Hash.length - srcOffset);
  // Actually: sha1[0xC..0x14] + unused[0..0x28] + kirkBlock[0..0x90-0x14-0x28+0xC]
  // In C: kirk7(sha1+0xC, sha1+0xC, 0xA0, key) — sha1/unused/kirkBlock are contiguous
  // Build contiguous: sha1(0x14) + unused(0x28) + kirkBlock(0x90) = 0xCC total, decrypt 0xA0 starting at +0xC
  const contiguous = concatBytes(type1.sha1Hash, type1.unused, type1.kirkBlock);
  const toDecrypt = contiguous.slice(srcOffset, srcOffset + 0xA0);
  const decryptedBlock = await kirk7(toDecrypt, pti.code);
  contiguous.set(decryptedBlock, srcOffset);
  // Copy back
  type1.sha1Hash.set(contiguous.subarray(0, 0x14));
  type1.unused.set(contiguous.subarray(0x14, 0x14 + 0x28));
  type1.kirkBlock.set(contiguous.subarray(0x14 + 0x28, 0x14 + 0x28 + 0x90));

  // SHA1 verification
  const shaData = concatBytes(xorbuf.slice(0, 0x14), type1.unused, type1.kirkBlock, type1.prxHeader);
  const computedSha1 = await sha1(shaData);
  if (!arraysEqual(computedSha1, type1.sha1Hash)) return -3;

  const offset = PSP_HEADER_SIZE - KIRK_CMD1_HEADER_SIZE - PRX_HEADER_SIZE;
  const outbuf = new Uint8Array(size);
  outbuf.set(inbuf.subarray(0, size));

  const headerBuf = new Uint8Array(KIRK_CMD1_HEADER_SIZE + PRX_HEADER_SIZE);
  headerBuf.set(type1.kirkBlock, 0);
  headerBuf.set(type1.prxHeader, KIRK_CMD1_HEADER_SIZE);

  const decryptedHeader = await decryptKirkHeaderType0(type1.kirkBlock, xorbuf, pti.code);
  headerBuf.set(decryptedHeader, 0);

  outbuf.set(headerBuf, offset);

  const kirkInput = outbuf.slice(offset, size);
  const ds = readU32LE(kirkInput, 0x70);
  const doff = readU32LE(kirkInput, 0x74);
  const mode = readU32LE(kirkInput, 0x60);
  log.debug(`type1: mode=${mode} data_size=${ds} data_offset=${doff} kirkInput.len=${kirkInput.length}`);
  log.debug(`type1: kirk header[0:16]=${Array.from(kirkInput.slice(0,16)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type1: kirk header[0x20:0x30]=${Array.from(kirkInput.slice(0x20,0x30)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type1: kirk header[0x30:0x40]=${Array.from(kirkInput.slice(0x30,0x40)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type1: kirk header[0x60:0x80]=${Array.from(kirkInput.slice(0x60,0x80)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  const decrypted = await kirkCMD1(kirkInput);
  if (!decrypted) return -4;

  inbuf.set(decrypted, 0);
  return decryptSize;
}

async function pspDecryptType2(inbuf: Uint8Array, size: number): Promise<number> {
  const decryptSize = readU32LE(inbuf, 0xB0) | 0;
  const tag = readU32LE(inbuf, 0xD0);
  const pti = getTagInfo2(tag);
  if (!pti) return -1;

  // Check range 0xD4..0xD4+0x58 is zero
  for (let i = 0xD4; i < 0xD4 + 0x58; i++) {
    if (inbuf[i] !== 0) return -2;
  }

  const xorbuf = await expandSeed(pti.key, pti.code);
  const type2 = buildPRXType2(inbuf);

  // Decrypt id through the kirkHeader (0x60 contiguous bytes: id/sha1/kirkHeader) with kirk7.
  // In C: kirk7(id, id, 0x60, key).
  const contig = concatBytes(type2.id, type2.sha1Hash, type2.kirkHeader);
  const decContig = await kirk7(contig.slice(0, 0x60), pti.code);
  type2.id.set(decContig.subarray(0, 0x10));
  type2.sha1Hash.set(decContig.subarray(0x10, 0x24));
  type2.kirkHeader.set(decContig.subarray(0x24, 0x60), 0); // only first 0x3C bytes

  // SHA1 verification
  const shaData = concatBytes(type2.tag, xorbuf.slice(0, 0x10), type2.empty, type2.id, type2.kirkHeader, type2.kirkMetadata, type2.prxHeader);
  const computedSha1 = await sha1(shaData);
  if (!arraysEqual(computedSha1, type2.sha1Hash)) return -3;

  const offset = PSP_HEADER_SIZE - KIRK_CMD1_HEADER_SIZE - PRX_HEADER_SIZE;
  const outbuf = new Uint8Array(size);
  outbuf.set(inbuf.subarray(0, size));

  // Build KIRK_CMD1 header: zeroed 0x90 bytes, then copy metadata at data_size offset (0x70), then prxHeader
  const header = new Uint8Array(KIRK_CMD1_HEADER_SIZE + PRX_HEADER_SIZE);
  // data_size is at offset 0x70 in KIRK_CMD1_HEADER
  header.set(type2.kirkMetadata, 0x70);
  header.set(type2.prxHeader, KIRK_CMD1_HEADER_SIZE);

  // decryptKirkHeader on first 0x40 bytes
  const decKirk = await decryptKirkHeader(type2.kirkHeader, 0x10, xorbuf, pti.code);
  header.set(decKirk, 0);
  // Set mode = 1
  writeU32LE(header, 0x60, 1);

  outbuf.set(header, offset);

  const kirkInput = outbuf.slice(offset, size);
  log.debug(`type2: kirkInput offset=${offset} len=${kirkInput.length}`);
  log.debug(`type2: header[0:16]=${Array.from(header.slice(0,16)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type2: header[0x10:0x20]=${Array.from(header.slice(0x10,0x20)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type2: header[0x20:0x30]=${Array.from(header.slice(0x20,0x30)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type2: header[0x30:0x40]=${Array.from(header.slice(0x30,0x40)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type2: header[0x60:0x70]=${Array.from(header.slice(0x60,0x70)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  log.debug(`type2: header[0x70:0x80]=${Array.from(header.slice(0x70,0x80)).map(b=>b.toString(16).padStart(2,'0')).join(' ')}`);
  const decrypted = await kirkCMD1(kirkInput);
  if (!decrypted) return -4;

  inbuf.set(decrypted, 0);
  return decryptSize;
}

async function pspDecryptType5(inbuf: Uint8Array, size: number, seed?: Uint8Array): Promise<number> {
  const decryptSize = readU32LE(inbuf, 0xB0) | 0;
  const tag = readU32LE(inbuf, 0xD0);
  const pti = getTagInfo2(tag);
  if (!pti) return -1;

  // Check range 0xD4+1..0xD4+0x58 is zero (note: +1)
  for (let i = 0xD4 + 1; i < 0xD4 + 0x58; i++) {
    if (inbuf[i] !== 0) return -2;
  }

  const xorbuf = await expandSeed(pti.key, pti.code, seed);
  const type5 = buildPRXType2(inbuf); // same layout

  // Type5 decrypt: two-step
  // Step 1: decrypt kirkHeader + sha1[0..0x10] (0x50 bytes) with XOR
  const data = new Uint8Array(0x50);
  data.set(type5.kirkHeader, 0);
  data.set(type5.sha1Hash.subarray(0, 0x10), 0x40);
  for (let i = 0; i < 0x50; i++) {
    if (pti.seed) data[i]! ^= pti.seed[i % 0x10]!;
    if (seed) data[i]! ^= seed[i % 0x10]!;
  }
  const decData = await kirk7(data, pti.code);
  type5.kirkHeader.set(decData.subarray(0, 0x40));
  type5.sha1Hash.set(decData.subarray(0x40, 0x50), 0);

  // Step 2: XOR id through kirkHeader then kirk7
  const idBlock = concatBytes(type5.id, type5.sha1Hash, type5.kirkHeader);
  if (pti.seed) {
    for (let i = 0; i < 0x60; i++) {
      idBlock[i]! ^= pti.seed[i % 0x10]!;
    }
  }
  const decIdBlock = await kirk7(idBlock.slice(0, 0x60), pti.code);
  type5.id.set(decIdBlock.subarray(0, 0x10));
  type5.sha1Hash.set(decIdBlock.subarray(0x10, 0x24));
  type5.kirkHeader.set(decIdBlock.subarray(0x24, 0x60), 0);

  // SHA1 verification
  const shaData = concatBytes(type5.tag, xorbuf.slice(0, 0x10), type5.empty, type5.id, type5.kirkHeader, type5.kirkMetadata, type5.prxHeader);
  const computedSha1 = await sha1(shaData);
  if (!arraysEqual(computedSha1, type5.sha1Hash)) return -3;

  const offset = PSP_HEADER_SIZE - KIRK_CMD1_HEADER_SIZE - PRX_HEADER_SIZE;
  const outbuf = new Uint8Array(size);
  outbuf.set(inbuf.subarray(0, size));

  const header = new Uint8Array(KIRK_CMD1_HEADER_SIZE + PRX_HEADER_SIZE);
  header.set(type5.kirkMetadata, 0x70);
  header.set(type5.prxHeader, KIRK_CMD1_HEADER_SIZE);

  const decKirk = await decryptKirkHeader(type5.kirkHeader, 0x10, xorbuf, pti.code);
  header.set(decKirk, 0);
  writeU32LE(header, 0x60, 1);

  outbuf.set(header, offset);

  const kirkInput = outbuf.slice(offset, size);
  const decrypted = await kirkCMD1(kirkInput);
  if (!decrypted) return -4;

  inbuf.set(decrypted, 0);
  return decryptSize;
}

async function pspDecryptType6(inbuf: Uint8Array, size: number): Promise<number> {
  const decryptSize = readU32LE(inbuf, 0xB0) | 0;
  const tag = readU32LE(inbuf, 0xD0);
  const pti = getTagInfo2(tag);
  if (!pti) return -1;

  // Check range 0xD4..0xD4+0x38 is zero
  for (let i = 0xD4; i < 0xD4 + 0x38; i++) {
    if (inbuf[i] !== 0) return -2;
  }

  const xorbuf = await expandSeed(pti.key, pti.code);
  const type6 = buildPRXType6(inbuf);

  // Decrypt id (0x60 bytes)
  const contig = concatBytes(type6.id, type6.sha1Hash, type6.kirkHeader);
  const decContig = await kirk7(contig.slice(0, 0x60), pti.code);
  type6.id.set(decContig.subarray(0, 0x10));
  type6.sha1Hash.set(decContig.subarray(0x10, 0x24));
  type6.kirkHeader.set(decContig.subarray(0x24, 0x60), 0);

  // SHA1 verification
  const shaData = concatBytes(type6.tag, xorbuf.slice(0, 0x10), type6.empty, type6.ecdsaSignatureTail, type6.id, type6.kirkHeader, type6.kirkMetadata, type6.prxHeader);
  const computedSha1 = await sha1(shaData);
  if (!arraysEqual(computedSha1, type6.sha1Hash)) return -3;

  // Type6 uses ECDSA header (also 0x90 bytes)
  const offset = PSP_HEADER_SIZE - KIRK_CMD1_ECDSA_HEADER_SIZE - PRX_HEADER_SIZE;
  const outbuf = new Uint8Array(size);
  outbuf.set(inbuf.subarray(0, size));

  const header = new Uint8Array(KIRK_CMD1_ECDSA_HEADER_SIZE + PRX_HEADER_SIZE);
  // Copy ecdsa signature tail at offset 0x40
  header.set(type6.ecdsaSignatureTail, 0x40);
  header.set(type6.kirkMetadata, 0x70);
  header.set(type6.prxHeader, KIRK_CMD1_ECDSA_HEADER_SIZE);

  const decKirk = await decryptKirkHeader(type6.kirkHeader, 0x10, xorbuf, pti.code);
  header.set(decKirk, 0);
  writeU32LE(header, 0x60, 1);   // mode = 1
  header[0x64] = 1;               // ecdsa_hash = 1

  outbuf.set(header, offset);

  const kirkInput = outbuf.slice(offset, size);
  const decrypted = await kirkCMD1(kirkInput);
  if (!decrypted) return -4;

  inbuf.set(decrypted, 0);
  return decryptSize;
}

// ===== Main entry point =====

export async function pspDecryptPRX(inbuf: Uint8Array, seed?: Uint8Array): Promise<Uint8Array | null> {
  const size = inbuf.length;
  if (size < PSP_HEADER_SIZE) return null;

  const tag = readU32LE(inbuf, 0xD0);
  const decryptSize = readU32LE(inbuf, 0xB0);
  log.debug(`tag=0x${tag.toString(16).padStart(8,'0')} decryptSize=${decryptSize} totalSize=${size}`);

  const types = [
    ["type0", () => pspDecryptType0(inbuf, size)] as const,
    ["type1", () => pspDecryptType1(inbuf, size)] as const,
    ["type2", () => pspDecryptType2(inbuf, size)] as const,
    ["type5", () => pspDecryptType5(inbuf, size, seed)] as const,
    ["type6", () => pspDecryptType6(inbuf, size)] as const,
  ];

  for (const [name, fn] of types) {
    try {
      const res = await fn();
      if (res >= 0) {
        log.debug(`${name} succeeded, decrypted ${res} bytes`);
        return inbuf.slice(0, res);
      }
      log.debug(`${name} returned ${res} (no match)`);
    } catch (err) {
      log.debug(`${name} threw: ${err}`);
    }
  }

  log.warn(`All decrypt types failed for tag 0x${tag.toString(16).padStart(8,'0')}`);
  return null;
}
